const targets = $('Fetch Active Targets').all().map(i => i.json);
const results = [];

for (const target of targets) {
  let url = target.site_url || '';
  if (!url.startsWith('http://') && !url.startsWith('https://')) {
    url = 'https://' + url;
  }
  results.push({
    json: {
      id: target.id,
      site_url: url,
      proxy_url: target.proxy_url,
      proxy_type: target.proxy_type
    }
  });
}

return results;

const input = $input.all();
const splitItems = $('Split Targets').all();
const results = [];

for (let i = 0; i < splitItems.length; i++) {
  const target = splitItems[i].json;
  const r = input[i]?.json || {};

  // Detect connection-level errors (ECONNREFUSED, ETIMEDOUT, ENOTFOUND, etc.)
  const errMsg = r.error || r.message || '';
  const errStr = typeof errMsg === 'object' ? JSON.stringify(errMsg) : String(errMsg);
  const isConnectionError = errStr.includes('ECONNREFUSED') || errStr.includes('ETIMEDOUT') || errStr.includes('ENOTFOUND') || errStr.includes('ECONNRESET') || errStr.includes('ECONNABORTED') || errStr.includes('CERT_') || errStr.includes('socket hang up');

  // If we got any HTTP status code (even 404, 403, 500), the server is alive
  const statusCode = r.statusCode || 0;
  const hasHttpResponse = statusCode > 0;

  // Site is OK if: we got an HTTP response OR no connection error detected
  // With neverError, successful responses come back as data (no error fields)
  const isOk = hasHttpResponse ? true : !isConnectionError && !r.error;

  let pingError = null;
  if (!isOk) {
    pingError = isConnectionError ? errStr.substring(0, 200) : (errStr || 'No response');
  }

  results.push({
    json: {
      id: target.id,
      ping_ok: isOk,
      ping_error: pingError
    }
  });
}

return results;

